mapper.select:
select r.room_id, r.room_no
from room r
where r.floor = #{floor}
and r.building = #{building}
and r.del_flag = '0'
order by r.room_no

select b.*
from bed b, room r
where b.room_id = r.room_id
and b.del_flag = '0'
and r.del_flag = '0'
and b.bed_no = #{bedNo}
and r.room_no = #{roomNo}
and r.building = #{building}

mapper.update:
update bed
set status = 'free'
where bed_id = #{bedId}

update bed
set status = 'out'
where bed_id = #{bedId}

update bed
set status = 'used'
where bed_id = #{bedId}
